+    if parsed.host().is_some_and(|value| value.is_ipv4() || value.is_ipv6()) && !allow_test_endpoints {
+        return Err(FcpError::InvalidRequest {
+            code: 1003,
+            message: format!("{field_name} must not use an IP literal"),
+        });
+    }
